def categorize_cross(cross_description):
    cross_description = cross_description.lower()
    if 'body of jesus' in cross_description or 'crucifix' in cross_description:
        return 'Catholic'
    elif 'empty cross' in cross_description and 'slanted footbar' in cross_description:
        return 'Eastern Orthodox'
    elif 'empty cross' in cross_description:
        return 'Protestant'
    elif 'torture stake' in cross_description or 'impaled jesus' in cross_description:
        return 'Jehovah\'s Witnesses'
    else:
        return 'Unknown'

# Example usage:
print(categorize_cross("A cross with the body of Jesus on it"))  # Output: Catholic
print(categorize_cross("An empty cross with a slanted footbar"))  # Output: Eastern Orthodox
